'use strict';

const express = require('express');

function applyHeaders(setter) {
  setter('X-Frame-Options', 'DENY');
  setter('X-Content-Type-Options', 'nosniff');
  setter('X-XSS-Protection', '1; mode=block');
  setter('Referrer-Policy', 'no-referrer');
  if (process.env.FORTRESS_HSTS === 'true') {
    setter('Strict-Transport-Security', 'max-age=31536000; includeSubDomains; preload');
  }
}

function middleware(req, res, next) {
  applyHeaders((name, value) => {
    if (typeof res.setHeader === 'function') {
      res.setHeader(name, value);
    } else if (typeof res.set === 'function') {
      res.set(name, value);
    }
  });
  if (typeof next === 'function') next();
}

async function koa(ctx, next) {
  applyHeaders((name, value) => {
    if (ctx && typeof ctx.set === 'function') {
      ctx.set(name, value);
    } else if (ctx && ctx.response && typeof ctx.response.set === 'function') {
      ctx.response.set(name, value);
    }
  });
  await next();
}

const router = express.Router();
router.get('/status/fo', (req, res) => {
  res.status(200).json({ status: 'ok', fortress: true });
});

module.exports = { middleware, koa, router };

